import urllib.request, json, websocket
with urllib.request.urlopen('http://127.0.0.1:9222/json') as r:
    tabs = json.loads(r.read().decode())
    ws_url = next(t['webSocketDebuggerUrl'] for t in tabs if 'colab.research.google.com/drive/' in t.get('url', ''))
ws = websocket.create_connection(ws_url)
js = '''
(function() {
    return colab.global.notebookModel.cells.map((cell, idx) => {
        let text = cell.textModel ? cell.textModel.getValue() : '';
        let outputs = [];
        if (cell.outputs && typeof cell.outputs.getLength === 'function') {
            for (let i = 0; i < cell.outputs.getLength(); i++) {
                outputs.push(cell.outputs.get(i));
            }
        } else if (cell.outputs && typeof cell.outputs.forEach === 'function') {
            cell.outputs.forEach(out => outputs.push(out));
        } else if (Array.isArray(cell.outputs)) {
            outputs = cell.outputs;
        }
        return {
            index: idx,
            type: cell.type,
            source: text.substring(0, 120),
            outputs: outputs.map(o => {
                if (o.text) return o.text;
                if (o.data) {
                    if (o.data['text/plain']) return o.data['text/plain'];
                }
                return JSON.stringify(o);
            })
        };
    });
})()
'''
ws.send(json.dumps({'id': 1, 'method': 'Runtime.evaluate', 'params': {'expression': js, 'returnByValue': True}}))
res = json.loads(ws.recv())
cells = res['result']['result']['value']
for c in cells:
    print(f'Cell {c[\"index\"]} ({c[\"type\"]}):')
    print(f'  Source: {repr(c[\"source\"])}')
    print(f'  Outputs: {repr(c[\"outputs\"])}')
"
